mapper.select:
SELECT s.id, s.amount, s.payment_method AS paymentMethod, s.sale_date AS saleDate, s.memo, m.name AS memberName, p.name AS productName FROM sale s LEFT JOIN member m ON s.member_id=m.id LEFT JOIN product p ON s.product_id=p.id WHERE s.product_type=#{category}
AND s.sale_date BETWEEN DATE_SUB(#{date}, INTERVAL WEEKDAY(#{date}) DAY) AND DATE_ADD(DATE_SUB(#{date}, INTERVAL WEEKDAY(#{date}) DAY), INTERVAL 6 DAY)
AND DATE_FORMAT(s.sale_date, '%Y-%m') = DATE_FORMAT(#{date}, '%Y-%m')
AND s.sale_date=#{date}
ORDER BY s.sale_date DESC, s.id DESC

SELECT COUNT(*) AS total, SUM(CASE WHEN m.gender='MALE' THEN 1 ELSE 0 END) AS male, SUM(CASE WHEN m.gender='FEMALE' THEN 1 ELSE 0 END) AS female FROM attendance a JOIN member m ON a.member_id=m.id
AND a.attend_date BETWEEN DATE_SUB(#{date}, INTERVAL WEEKDAY(#{date}) DAY) AND DATE_ADD(DATE_SUB(#{date}, INTERVAL WEEKDAY(#{date}) DAY), INTERVAL 6 DAY)
AND DATE_FORMAT(a.attend_date, '%Y-%m') = DATE_FORMAT(#{date}, '%Y-%m')
AND a.attend_date=#{date}
AND a.type=#{type}
